const trigger = $('Report Form Webhook').first()?.json ?? $('When clicking \'Execute workflow\'').first()?.json ?? {};
const request = trigger.query ?? trigger.body ?? trigger ?? {};
const headers = trigger.headers ?? {};
const settings = $('Load Report Settings').first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const toArray = (value) => {
  if (Array.isArray(value)) return value.map(clean).filter(Boolean);
  const text = clean(value);
  return text ? [text] : [];
};
const deriveBaseUrl = (inputHeaders, fallback) => {
  const forwardedProto = clean(inputHeaders['x-forwarded-proto']);
  const forwardedHost = clean(inputHeaders['x-forwarded-host']);
  const host = forwardedHost || clean(inputHeaders.host);
  const forwardedPort = clean(inputHeaders['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const parseJsonSetting = (value, fallback) => {
  const text = clean(value);
  if (!text) return fallback;
  try {
    return JSON.parse(text);
  } catch (error) {
    throw new Error(`Invalid JSON in global settings: ${error.message}`);
  }
};
const dashboards = parseJsonSetting(settings.metabase_report_dashboards_json, []);
const profiles = parseJsonSetting(settings.metabase_report_redaction_profiles_json, []);
if (!dashboards.length) throw new Error('global_settings.metabase_report_dashboards_json is empty.');
const selectedDashboardId = clean(request.dashboard_id) || String(dashboards[0].id);
const selectedMode = clean(request.report_mode) || 'redact';
const selectedProfileId = clean(request.redaction_profile) || clean(profiles[0]?.id);
const selectedYear = clean(request.year);
const selectedSearch = clean(request.search);
const selectedOutputName = clean(request.output_name);
const selectedExtraTerms = clean(request.extra_redaction_terms);
const selectedTabs = toArray(request['tabs[]'] ?? request.tabs);
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const actionUrl = `${deriveBaseUrl(headers, fallbackBaseUrl)}/webhook/report-generate`;
const html = [
  '<!doctype html>',
  '<html lang="en">',
  '<head>',
  '  <meta charset="utf-8">',
  '  <meta name="viewport" content="width=device-width, initial-scale=1">',
  '  <title>Metabase Report PDF</title>',
  '  <style>',
  '    :root { color-scheme: light; --bg: #f7f8fc; --panel: #ffffff; --ink: #2e3d4e; --muted: #6b7785; --line: #e2e8f0; --accent: #509ee3; --accent-dark: #2f80d8; --soft: #f2f7fd; --warning: #fff7e6; --warning-line: #f1cf7a; }',
  '    * { box-sizing: border-box; }',
  '    body { margin: 0; padding: 24px; min-height: 100vh; font-family: Lato, Helvetica Neue, Arial, sans-serif; background: linear-gradient(180deg, #fbfcfe 0%, var(--bg) 100%); color: var(--ink); }',
  '    .wrap { max-width: 920px; margin: 0 auto; background: var(--panel); border: 1px solid var(--line); border-radius: 18px; padding: 28px; box-shadow: 0 18px 40px rgba(53, 72, 91, 0.08); }',
  '    h1 { margin: 0 0 10px; font-size: 30px; line-height: 1.1; letter-spacing: -0.02em; }',
  '    .lede { margin: 0 0 18px; color: var(--muted); font-size: 16px; }',
  '    .warning { margin: 0 0 22px; padding: 14px 16px; border-radius: 12px; background: var(--warning); border: 1px solid var(--warning-line); color: #7a5a00; }',
  '    form { display: grid; gap: 18px; }',
  '    .grid { display: grid; gap: 16px; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); }',
  '    label { display: block; font-weight: 700; margin-bottom: 6px; }',
  '    input, select, textarea { width: 100%; border: 1px solid var(--line); border-radius: 10px; padding: 10px 12px; font: inherit; color: var(--ink); background: #fff; }',
  '    textarea { min-height: 120px; resize: vertical; }',
  '    .help { margin-top: 4px; color: var(--muted); font-size: 13px; }',
  '    .tabs { display: grid; gap: 10px; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); }',
  '    .tab-option { display: flex; align-items: center; gap: 10px; padding: 10px 12px; border: 1px solid var(--line); border-radius: 10px; background: #fff; }',
  '    .tab-option input { width: auto; margin: 0; }',
  '    .actions { display: flex; gap: 12px; flex-wrap: wrap; align-items: center; }',
  '    button { appearance: none; border: 0; border-radius: 999px; padding: 12px 18px; font: inherit; font-weight: 700; cursor: pointer; color: white; background: linear-gradient(135deg, var(--accent) 0%, var(--accent-dark) 100%); box-shadow: 0 10px 24px rgba(80, 158, 227, 0.22); }',
  '    .meta { color: var(--muted); font-size: 14px; }',
  '    .mode-help { padding: 12px 14px; border-radius: 12px; background: var(--soft); border: 1px solid #d8e7f7; color: var(--muted); font-size: 14px; }',
  '    [hidden] { display: none !important; }',
  '  </style>',
  '</head>',
  '<body>',
  '  <div class="wrap">',
  '    <h1>Metabase Report PDF</h1>',
  '    <p class="lede">Choose a dashboard, select the tab names to include, and generate a PDF through the local Playwright exporter and Stirling PDF.</p>',
  '    <p class="warning">Redact keeps the original values visible to the renderer and then masks them in the PDF. Anonymise keeps the same dashboard layout but replaces configured PII table values with consistent fake data during export.</p>',
  `    <form action="${escapeHtml(actionUrl)}" method="post">`,
  '      <div class="grid">',
  '        <div>',
  '          <label for="dashboard_id">Dashboard</label>',
  `          <select id="dashboard_id" name="dashboard_id">${dashboards.map((dashboard) => `<option value="${escapeHtml(dashboard.id)}"${String(dashboard.id) === selectedDashboardId ? ' selected' : ''}>${escapeHtml(dashboard.name)}</option>`).join('')}</select>`,
  '          <div class="help">Dashboards come from <code>global_settings.metabase_report_dashboards_json</code>.</div>',
  '        </div>',
  '        <div>',
  '          <label for="report_mode">Mode</label>',
  `          <select id="report_mode" name="report_mode"><option value="redact"${selectedMode === 'redact' ? ' selected' : ''}>Redact</option><option value="anonymise"${selectedMode === 'anonymise' ? ' selected' : ''}>Anonymise</option></select>`,
  '          <div class="help">Redact uses Stirling auto-redact. Anonymise pseudonymises configured PII columns directly in the rendered report.</div>',
  '        </div>',
  '        <div>',
  '          <label for="output_name">Output name</label>',
  `          <input id="output_name" name="output_name" type="text" value="${escapeHtml(selectedOutputName)}" placeholder="avondale-membership-report">`,
  '          <div class="help">Leave blank to derive a filename automatically.</div>',
  '        </div>',
  '      </div>',
  '      <div class="grid">',
  '        <div>',
  '          <label for="year">Year filter</label>',
  `          <input id="year" name="year" type="text" value="${escapeHtml(selectedYear)}" placeholder="2026">`,
  '        </div>',
  '        <div>',
  '          <label for="search">Search filter</label>',
  `          <input id="search" name="search" type="text" value="${escapeHtml(selectedSearch)}" placeholder="Optional dashboard search filter">`,
  '        </div>',
  '      </div>',
  '      <div>',
  '        <label>Tabs to include</label>',
  '        <div class="help">These are the tab names the Playwright exporter will click and print in order.</div>',
  '        <div class="tabs" data-tabs></div>',
  '      </div>',
  '      <div class="mode-help" id="anonymise-help" hidden>Anonymise mode pseudonymises configured PII columns with stable fake values that stay consistent across the whole report run.</div>',
  '      <section id="redaction-section">',
  '        <div class="grid">',
  '          <div>',
  '            <label for="redaction_profile">Redaction profile</label>',
  `            <select id="redaction_profile" name="redaction_profile">${profiles.map((profile) => `<option value="${escapeHtml(profile.id)}"${String(profile.id) === selectedProfileId ? ' selected' : ''}>${escapeHtml(profile.name)}</option>`).join('')}</select>`,
  '            <div class="help">Profiles come from <code>global_settings.metabase_report_redaction_profiles_json</code>.</div>',
  '          </div>',
  '        </div>',
  '        <div>',
  '          <label for="extra_redaction_terms">Extra redact terms</label>',
  `          <textarea id="extra_redaction_terms" name="extra_redaction_terms" placeholder="Add one name, phrase, or regex per line">${escapeHtml(selectedExtraTerms)}</textarea>`,
  '          <div class="help">These terms are appended to the selected profile before Stirling auto-redact runs.</div>',
  '        </div>',
  '      </section>',
  '      <div class="actions">',
  '        <button type="submit">Generate PDF</button>',
  '        <span class="meta">The generated file is returned directly by the report workflow.</span>',
  '      </div>',
  '    </form>',
  '  </div>',
  `  <script>
       const dashboards = ${JSON.stringify(dashboards)};
       const initiallySelectedTabs = new Set(${JSON.stringify(selectedTabs)});
       const tabsHost = document.querySelector('[data-tabs]');
       const dashboardSelect = document.getElementById('dashboard_id');
       const modeSelect = document.getElementById('report_mode');
       const redactionSection = document.getElementById('redaction-section');
       const anonymiseHelp = document.getElementById('anonymise-help');
       const renderTabs = () => {
         const dashboard = dashboards.find((candidate) => String(candidate.id) === String(dashboardSelect.value)) || dashboards[0];
         const explicitSelection = initiallySelectedTabs.size > 0;
         const defaultTabs = new Set((dashboard.defaultTabs ?? []).map((value) => String(value)));
         tabsHost.innerHTML = (dashboard.tabs ?? []).map((tab) => {
           const checked = explicitSelection ? initiallySelectedTabs.has(String(tab.id)) : defaultTabs.has(String(tab.id));
           return '<label class="tab-option"><input type="checkbox" name="tabs[]" value="' + tab.id + '"' + (checked ? ' checked' : '') + '><span>' + tab.name + '</span></label>';
         }).join('');
       };
       const updateMode = () => {
         const isRedact = modeSelect.value === 'redact';
         redactionSection.hidden = !isRedact;
         anonymiseHelp.hidden = isRedact;
       };
       dashboardSelect.addEventListener('change', renderTabs);
       modeSelect.addEventListener('change', updateMode);
       renderTabs();
       updateMode();
     </script>`,
  '</body>',
  '</html>',
].join('\n');
return [{ json: { html } }];
